import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    distances_to_customers = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])
    distance_to_depot = distance(cur_truck_pos, depot_pos)

    avg_distance_to_depot = np.mean([distance(truck_pos, depot_pos) for truck_pos in all_truck_pos])
    min_distance_to_depot = min([distance(truck_pos, depot_pos) for truck_pos in all_truck_pos])

    # Calculate congestion metric: average distance of trucks to their nearest customer
    trucks_nearest_customer_distance = [
        min([distance(truck_pos, customer) for customer in unvisited_customers]) for truck_pos in all_truck_pos
    ]
    avg_nearest_customer_distance = np.mean(trucks_nearest_customer_distance)

    # Decide on strategy based on truck's current position relative to other trucks and customers
    if distances_to_customers.min() <= 0.7 * avg_distance_to_depot:
        # Closest customer is relatively closer
        best_node = np.argmin(distances_to_customers)
    elif distance_to_depot < min_distance_to_depot and np.random.rand() < 0.3:
        # If truck is closer than any other truck to the depot and randomly decides, it may wait
        return None
    elif distances_to_customers.min() > 1.2 * avg_nearest_customer_distance:
        # No customer is distinctly closer than average distance trucks have to their nearest customers
        if np.random.rand() < 0.5:
            return None  # Random waiting if out of inline strategic option
        best_node = np.argmin(distances_to_customers)
    else:
        # Default back to nearest customer
        best_node = np.argmin(distances_to_customers)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(a, b):
        return np.linalg.norm(a - b)

    if len(unvisited_customers) == 0:
        return None  # No unvisited customers available

    weights = np.zeros(len(unvisited_customers))

    for i, customer in enumerate(unvisited_customers):
        dist_to_customer = distance(cur_truck_pos, customer)
        congestion_incentive = 0

        proximity_penalty = sum(max(0, 1 - distance(truck_pos, customer) / dist_to_customer) for truck_pos in all_truck_pos if not np.array_equal(truck_pos, cur_truck_pos))

        for other_truck in all_truck_pos:
            if np.array_equal(other_truck, cur_truck_pos):
                continue
            # Reward moving towards isolated customers
            if distance(other_truck, customer) > 2 * dist_to_customer:
                congestion_incentive += 0.2

        isolation_score = 1 / (1 + proximity_penalty) + congestion_incentive
        direct_proximity_score = 1 / (1 + dist_to_customer)

        # Total weight calculation with added factor for remoteness
        weights[i] = 1.5 * direct_proximity_score + isolation_score

    best_node = np.argmax(weights)

    return best_node
